import { ApiError } from "@reeve/shared";
export async function postDetect(file) {
    const form = new FormData();
    form.append("file", file);
    const res = await fetch("/detect", { method: "POST", body: form });
    if (!res.ok)
        throw await toError(res);
    return (await res.json());
}
export async function postIdentify(file, bbox) {
    const form = new FormData();
    form.append("file", file);
    if (bbox)
        form.append("bbox", bbox.join(","));
    const res = await fetch("/identify", { method: "POST", body: form });
    if (!res.ok)
        throw await toError(res);
    return (await res.json());
}
async function toError(res) {
    let body = null;
    try {
        body = await res.json();
    }
    catch {
        try {
            body = await res.text();
        }
        catch {
            body = null;
        }
    }
    return new ApiError(res.status, body, res.url);
}
export function extractErrorMessage(err) {
    if (err instanceof ApiError) {
        const body = err.body;
        if (body && typeof body === "object" && "detail" in body && body.detail) {
            return String(body.detail);
        }
        if (typeof body === "string")
            return body;
        return `HTTP ${err.status}`;
    }
    if (err instanceof Error)
        return err.message;
    return String(err);
}
