export async function streamIdentify(file, onEvent, signal) {
    const form = new FormData();
    form.append("file", file);
    const res = await fetch("/identify/stream", { method: "POST", body: form, signal });
    if (!res.ok) {
        let detail = `HTTP ${res.status}`;
        try {
            const body = (await res.json());
            if (body.detail)
                detail = body.detail;
        }
        catch {
            /* ignore */
        }
        throw new Error(detail);
    }
    if (!res.body)
        throw new Error("응답 스트림을 사용할 수 없습니다");
    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    try {
        while (true) {
            const { value, done } = await reader.read();
            if (done)
                break;
            buffer += decoder.decode(value, { stream: true });
            const parts = buffer.split("\n\n");
            buffer = parts.pop() ?? "";
            for (const part of parts) {
                const line = part.trim();
                if (!line.startsWith("data:"))
                    continue;
                const raw = line.slice(5).trim();
                if (!raw)
                    continue;
                try {
                    onEvent(JSON.parse(raw));
                }
                catch {
                    /* ignore malformed event */
                }
            }
        }
    }
    finally {
        try {
            reader.releaseLock();
        }
        catch {
            /* noop */
        }
    }
}
export function toCsv(rows) {
    const header = ["번호", "파일명", "제조사", "모델", "신뢰도", "상태"];
    const data = rows.map((row, i) => [
        String(i + 1),
        row.file.name,
        row.error ? "" : row.manufacturer_korean ?? "",
        row.error ? "" : row.model_korean ?? "",
        row.error ? "" : row.confidence != null ? `${(row.confidence * 100).toFixed(1)}%` : "",
        row.error ? `실패: ${row.error}` : row.status ?? "",
    ]);
    const escape = (v) => `"${v.replace(/"/g, '""')}"`;
    return [header, ...data].map((r) => r.map(escape).join(",")).join("\n");
}
export function downloadCsv(csv, filename = "batch_results.csv") {
    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
}
const IMAGE_EXTS = new Set(["jpg", "jpeg", "png", "webp"]);
export function filterImages(files) {
    return Array.from(files).filter((f) => {
        const ext = f.name.split(".").pop()?.toLowerCase();
        return ext ? IMAGE_EXTS.has(ext) : false;
    });
}
export function formatSeconds(s) {
    if (!isFinite(s) || s < 0)
        return "-";
    if (s < 60)
        return `${s}초`;
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return sec > 0 ? `${m}분 ${sec}초` : `${m}분`;
}
