export function resolveStatus(item) {
    const title = item.message ?? undefined;
    if (item.error) {
        return {
            label: "실패",
            className: "bg-red-600 text-white",
            title: item.error,
        };
    }
    if (item.status === "identified") {
        return { label: "판별완료", className: "bg-emerald-600 text-white", title };
    }
    if (item.status === "low_confidence") {
        if (item.yolo_detected === false) {
            return { label: "감지실패", className: "bg-orange-500 text-white", title };
        }
        return { label: "저신뢰도", className: "bg-amber-400 text-black", title };
    }
    if (item.status === "no_match") {
        return { label: "미매칭", className: "bg-slate-500 text-white", title };
    }
    if (item.status === "yolo_failed") {
        return { label: "YOLO탐지실패", className: "bg-slate-700 text-white", title };
    }
    return { label: item.status ?? "-", className: "bg-slate-500 text-white", title };
}
export function resolveResultStatus(result) {
    return resolveStatus({
        status: result.status,
        yolo_detected: result.detection != null,
        message: result.message,
    });
}
